using Precept.Pipeline;

namespace Precept.Language;

public sealed record DiagnosticMeta(
    string             Code,
    DiagnosticStage    Stage,
    Severity           Severity,
    string             MessageTemplate,
    DiagnosticCategory Category,
    DiagnosticCode[]?  RelatedCodes  = null,
    string?            FixHint       = null,
    FaultCode?         PreventsFault = null
);

public static class Diagnostics
{
    public static DiagnosticMeta GetMeta(DiagnosticCode code) => code switch
    {
        // ── Lex ─────────────────────────────────────────────────────────────────
        DiagnosticCode.InputTooLarge                 => new(nameof(DiagnosticCode.InputTooLarge),                 DiagnosticStage.Lex,   Severity.Error,   "This definition exceeds the 65,536-character security limit and cannot be processed",                                                  DiagnosticCategory.Safety),
        DiagnosticCode.UnterminatedStringLiteral      => new(nameof(DiagnosticCode.UnterminatedStringLiteral),      DiagnosticStage.Lex,   Severity.Error,   "Text value opened with \" is missing its closing quote — every \" must have a matching \"",                                              DiagnosticCategory.Structure,
            FixHint: "Add a closing \" at the end of the text value"),
        DiagnosticCode.UnterminatedTypedConstant       => new(nameof(DiagnosticCode.UnterminatedTypedConstant),       DiagnosticStage.Lex,   Severity.Error,   "Value opened with ' is missing its closing quote — every ' must have a matching '",                                                     DiagnosticCategory.Structure,
            FixHint: "Add a closing ' at the end of the typed constant"),
        DiagnosticCode.UnterminatedInterpolation       => new(nameof(DiagnosticCode.UnterminatedInterpolation),       DiagnosticStage.Lex,   Severity.Error,   "The {{ }} section is not closed — add a closing }} on the same line",                                                                   DiagnosticCategory.Structure,
            FixHint: "Close the interpolation expression with }"),
        DiagnosticCode.InvalidCharacter                => new(nameof(DiagnosticCode.InvalidCharacter),                DiagnosticStage.Lex,   Severity.Error,   "'{0}' is not a valid character in a precept definition — remove or replace it",                                                         DiagnosticCategory.Structure),
        DiagnosticCode.UnrecognizedStringEscape        => new(nameof(DiagnosticCode.UnrecognizedStringEscape),        DiagnosticStage.Lex,   Severity.Error,   "'\\{0}' is not a valid escape in a text value — use \\\" for a quote, \\\\ for a backslash, \\n for a newline, or \\t for a tab",       DiagnosticCategory.Structure,
            FixHint: "Use \\\", \\\\, \\n, or \\t as valid escape sequences in text values"),
        DiagnosticCode.UnrecognizedTypedConstantEscape => new(nameof(DiagnosticCode.UnrecognizedTypedConstantEscape), DiagnosticStage.Lex,   Severity.Error,   "'\\{0}' is not a valid escape in a single-quoted value — use \\' for a quote, or \\\\ for a backslash",                                DiagnosticCategory.Structure,
            FixHint: "Use \\' or \\\\ as valid escape sequences in single-quoted values"),
        DiagnosticCode.UnescapedBraceInLiteral         => new(nameof(DiagnosticCode.UnescapedBraceInLiteral),         DiagnosticStage.Lex,   Severity.Error,   "Use '}}}}' to include a literal }} in this value — a single }} starts a field reference",                                               DiagnosticCategory.Structure,
            FixHint: "Double the brace: write }}}} to include a literal }} in the text value"),

        // ── Parse ────────────────────────────────────────────────────────────────
        DiagnosticCode.ExpectedToken              => new(nameof(DiagnosticCode.ExpectedToken),              DiagnosticStage.Parse, Severity.Error,   "Expected {0} here, but found '{1}'",                                                                                                    DiagnosticCategory.Structure),
        DiagnosticCode.UnexpectedKeyword          => new(nameof(DiagnosticCode.UnexpectedKeyword),          DiagnosticStage.Parse, Severity.Error,   "'{0}' cannot appear inside a {1}",                                                                                                     DiagnosticCategory.Structure),
        DiagnosticCode.NonAssociativeComparison   => new(nameof(DiagnosticCode.NonAssociativeComparison),   DiagnosticStage.Parse, Severity.Error,   "Comparisons like == and < cannot be chained — {0}",                                                                                    DiagnosticCategory.TypeSystem,
            FixHint: "Break the comparison into two separate conditions joined with 'and'"),
        DiagnosticCode.InvalidCallTarget          => new(nameof(DiagnosticCode.InvalidCallTarget),          DiagnosticStage.Parse, Severity.Error,   "Only built-in functions can be called this way — '{0}' is not a function name",                                                         DiagnosticCategory.Naming,
            RelatedCodes: [DiagnosticCode.UndeclaredFunction],
            FixHint: "Use a recognized built-in function name like min(), max(), abs(), or round()"),
        DiagnosticCode.MutuallyExclusiveQualifiers => new(nameof(DiagnosticCode.MutuallyExclusiveQualifiers), DiagnosticStage.Type, Severity.Error,  "'in' and 'of' qualifiers cannot both appear on this type — only 'price' supports both",                                                DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.QualifierMismatch],
            FixHint: "Use 'in' for currency, 'of' for unit, or both only on 'price' types"),

        // ── Type ─────────────────────────────────────────────────────────────────
        DiagnosticCode.UndeclaredField                => new(nameof(DiagnosticCode.UndeclaredField),                DiagnosticStage.Type,  Severity.Error,   "Field '{0}' is not declared",                                                                                                          DiagnosticCategory.Naming,
            RelatedCodes: [DiagnosticCode.DuplicateFieldName],
            FixHint: "Declare the field at the top of the precept using 'field Name as Type'",
            PreventsFault: FaultCode.UndeclaredField),
        DiagnosticCode.TypeMismatch                   => new(nameof(DiagnosticCode.TypeMismatch),                   DiagnosticStage.Type,  Severity.Error,   "Expected a {0} value here, but got '{1}'",                                                                                             DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.NullInNonNullableContext],
            PreventsFault: FaultCode.TypeMismatch),
        DiagnosticCode.NullInNonNullableContext       => new(nameof(DiagnosticCode.NullInNonNullableContext),       DiagnosticStage.Type,  Severity.Error,   "'{0}' requires a value and cannot be empty here",                                                                                      DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.TypeMismatch],
            FixHint: "Add the 'optional' modifier to the field declaration to allow null values",
            PreventsFault: FaultCode.UnexpectedNull),
        DiagnosticCode.InvalidMemberAccess            => new(nameof(DiagnosticCode.InvalidMemberAccess),            DiagnosticStage.Type,  Severity.Error,   "'.{0}' is not available on {1} fields",                                                                                                DiagnosticCategory.TypeSystem,
            FixHint: "Check the available accessors for this type in the language reference",
            PreventsFault: FaultCode.InvalidMemberAccess),
        DiagnosticCode.FunctionArityMismatch          => new(nameof(DiagnosticCode.FunctionArityMismatch),          DiagnosticStage.Type,  Severity.Error,   "'{0}' takes {1} inputs, but {2} were provided",                                                                                        DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.FunctionArgConstraintViolation],
            PreventsFault: FaultCode.FunctionArityMismatch),
        DiagnosticCode.FunctionArgConstraintViolation => new(nameof(DiagnosticCode.FunctionArgConstraintViolation), DiagnosticStage.Type,  Severity.Error,   "Value {0} for '{1}' is not valid: {2}",                                                                                                DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.FunctionArityMismatch],
            PreventsFault: FaultCode.FunctionArgConstraintViolation),
        DiagnosticCode.DuplicateFieldName             => new(nameof(DiagnosticCode.DuplicateFieldName),             DiagnosticStage.Type,  Severity.Error,   "Field '{0}' is already declared",                                                                                                      DiagnosticCategory.Naming,
            RelatedCodes: [DiagnosticCode.DuplicateStateName, DiagnosticCode.DuplicateEventName],
            FixHint: "Rename one of the fields to a unique name"),
        DiagnosticCode.DuplicateStateName             => new(nameof(DiagnosticCode.DuplicateStateName),             DiagnosticStage.Type,  Severity.Error,   "State '{0}' is already declared",                                                                                                      DiagnosticCategory.Naming,
            RelatedCodes: [DiagnosticCode.DuplicateFieldName, DiagnosticCode.DuplicateEventName],
            FixHint: "Rename one of the states to a unique name"),
        DiagnosticCode.DuplicateEventName             => new(nameof(DiagnosticCode.DuplicateEventName),             DiagnosticStage.Type,  Severity.Error,   "Event '{0}' is already declared",                                                                                                      DiagnosticCategory.Naming,
            RelatedCodes: [DiagnosticCode.DuplicateFieldName, DiagnosticCode.DuplicateStateName],
            FixHint: "Rename one of the events to a unique name"),
        DiagnosticCode.DuplicateArgName               => new(nameof(DiagnosticCode.DuplicateArgName),               DiagnosticStage.Type,  Severity.Error,   "Argument '{0}' is already declared on event '{1}'",                                                                                    DiagnosticCategory.Naming,
            FixHint: "Rename one of the event arguments to a unique name"),
        DiagnosticCode.UndeclaredState                => new(nameof(DiagnosticCode.UndeclaredState),                DiagnosticStage.Type,  Severity.Error,   "State '{0}' is not declared",                                                                                                          DiagnosticCategory.Naming,
            RelatedCodes: [DiagnosticCode.UndeclaredEvent, DiagnosticCode.UndeclaredField],
            FixHint: "Declare the state using 'state StateName' before referencing it"),
        DiagnosticCode.UndeclaredEvent                => new(nameof(DiagnosticCode.UndeclaredEvent),                DiagnosticStage.Type,  Severity.Error,   "Event '{0}' is not declared",                                                                                                          DiagnosticCategory.Naming,
            RelatedCodes: [DiagnosticCode.UndeclaredState, DiagnosticCode.UndeclaredField],
            FixHint: "Declare the event using 'event EventName' before referencing it"),
        DiagnosticCode.UndeclaredFunction             => new(nameof(DiagnosticCode.UndeclaredFunction),             DiagnosticStage.Type,  Severity.Error,   "'{0}' is not a recognized function",                                                                                                   DiagnosticCategory.Naming,
            RelatedCodes: [DiagnosticCode.InvalidCallTarget],
            FixHint: "Use a recognized built-in function name, or check the function catalog"),
        DiagnosticCode.MultipleInitialStates          => new(nameof(DiagnosticCode.MultipleInitialStates),          DiagnosticStage.Type,  Severity.Error,   "Only one state can be marked 'initial' — '{0}' and '{1}' both are",                                                                    DiagnosticCategory.Structure,
            RelatedCodes: [DiagnosticCode.NoInitialState],
            FixHint: "Remove 'initial' from all but one state"),
        DiagnosticCode.NoInitialState                 => new(nameof(DiagnosticCode.NoInitialState),                 DiagnosticStage.Type,  Severity.Error,   "This precept has states but none is marked 'initial'",                                                                                 DiagnosticCategory.Structure,
            RelatedCodes: [DiagnosticCode.MultipleInitialStates],
            FixHint: "Add 'initial' to the first state the precept starts in"),
        DiagnosticCode.InvalidModifierForType         => new(nameof(DiagnosticCode.InvalidModifierForType),         DiagnosticStage.Type,  Severity.Error,   "The '{0}' constraint does not apply to {1} fields",                                                                                    DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.InvalidModifierBounds, DiagnosticCode.InvalidModifierValue],
            FixHint: "Remove this constraint or change the field type to one that supports it"),
        DiagnosticCode.InvalidModifierBounds          => new(nameof(DiagnosticCode.InvalidModifierBounds),          DiagnosticStage.Type,  Severity.Error,   "{0} ({1}) cannot exceed {2} ({3})",                                                                                                    DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.InvalidModifierForType, DiagnosticCode.InvalidModifierValue],
            FixHint: "Ensure the lower bound is less than or equal to the upper bound"),
        DiagnosticCode.InvalidModifierValue           => new(nameof(DiagnosticCode.InvalidModifierValue),           DiagnosticStage.Type,  Severity.Error,   "The value for '{0}' must be {1}",                                                                                                      DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.InvalidModifierForType, DiagnosticCode.InvalidModifierBounds]),
        DiagnosticCode.DuplicateModifier              => new(nameof(DiagnosticCode.DuplicateModifier),              DiagnosticStage.Type,  Severity.Error,   "The '{0}' constraint is already applied to this field",                                                                                DiagnosticCategory.TypeSystem,
            FixHint: "Remove the duplicate constraint declaration"),
        DiagnosticCode.RedundantModifier              => new(nameof(DiagnosticCode.RedundantModifier),              DiagnosticStage.Type,  Severity.Warning, "'{0}' is unnecessary — '{1}' already implies it",                                                                                      DiagnosticCategory.TypeSystem,
            FixHint: "Remove the redundant constraint — the implied modifier already covers it"),
        DiagnosticCode.ComputedFieldNotWritable       => new(nameof(DiagnosticCode.ComputedFieldNotWritable),       DiagnosticStage.Type,  Severity.Error,   "Field '{0}' is computed and cannot be assigned",                                                                                       DiagnosticCategory.Structure,
            RelatedCodes: [DiagnosticCode.ComputedFieldWithDefault, DiagnosticCode.CircularComputedField],
            FixHint: "Remove the assignment — this field's value is derived automatically"),
        DiagnosticCode.ComputedFieldWithDefault       => new(nameof(DiagnosticCode.ComputedFieldWithDefault),       DiagnosticStage.Type,  Severity.Error,   "Field '{0}' is computed and cannot have a default value",                                                                              DiagnosticCategory.Structure,
            RelatedCodes: [DiagnosticCode.ComputedFieldNotWritable, DiagnosticCode.CircularComputedField],
            FixHint: "Remove the default clause — computed fields cannot have explicit defaults"),
        DiagnosticCode.CircularComputedField          => new(nameof(DiagnosticCode.CircularComputedField),          DiagnosticStage.Type,  Severity.Error,   "Computed field '{0}' has a circular dependency: {1}",                                                                                  DiagnosticCategory.Structure,
            RelatedCodes: [DiagnosticCode.ComputedFieldNotWritable, DiagnosticCode.ComputedFieldWithDefault],
            FixHint: "Restructure the computed fields to break the circular dependency"),
        DiagnosticCode.ConflictingAccessModes         => new(nameof(DiagnosticCode.ConflictingAccessModes),         DiagnosticStage.Type,  Severity.Error,   "Field '{0}' has conflicting access modes in state '{1}'",                                                                              DiagnosticCategory.Structure,
            FixHint: "Ensure each field has at most one access mode per state"),
        DiagnosticCode.ListLiteralOutsideDefault      => new(nameof(DiagnosticCode.ListLiteralOutsideDefault),      DiagnosticStage.Type,  Severity.Error,   "List values can only appear in default clauses",                                                                                       DiagnosticCategory.Structure,
            FixHint: "Move the list value into a 'default' clause on the field declaration"),
        DiagnosticCode.DuplicateChoiceValue           => new(nameof(DiagnosticCode.DuplicateChoiceValue),           DiagnosticStage.Type,  Severity.Error,   "Choice value '{0}' is duplicated",                                                                                                     DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.EmptyChoice],
            FixHint: "Remove the duplicate value from the choice type"),
        DiagnosticCode.EmptyChoice                    => new(nameof(DiagnosticCode.EmptyChoice),                    DiagnosticStage.Type,  Severity.Error,   "A choice type must have at least one value",                                                                                           DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.DuplicateChoiceValue],
            FixHint: "Add at least one value to the choice type"),
        DiagnosticCode.CollectionOperationOnScalar    => new(nameof(DiagnosticCode.CollectionOperationOnScalar),    DiagnosticStage.Type,  Severity.Error,   "'{0}' is a {1} operation, but '{2}' is not a {1}",                                                                                     DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.ScalarOperationOnCollection],
            FixHint: "Change the field type to a collection (set, queue, or stack) for collection operations"),
        DiagnosticCode.ScalarOperationOnCollection    => new(nameof(DiagnosticCode.ScalarOperationOnCollection),    DiagnosticStage.Type,  Severity.Error,   "'{0}' cannot be used with collection field '{1}'",                                                                                     DiagnosticCategory.TypeSystem,
            RelatedCodes: [DiagnosticCode.CollectionOperationOnScalar],
            FixHint: "Use a collection action (add, remove, enqueue, push) for collection fields"),
        DiagnosticCode.IsSetOnNonOptional             => new(nameof(DiagnosticCode.IsSetOnNonOptional),             DiagnosticStage.Type,  Severity.Error,   "'{0}' always has a value — 'is set' only works on optional fields",                                                                    DiagnosticCategory.TypeSystem,
            FixHint: "Remove the 'is set' check, or add 'optional' to the field to make it nullable"),
        DiagnosticCode.EventArgOutOfScope             => new(nameof(DiagnosticCode.EventArgOutOfScope),             DiagnosticStage.Type,  Severity.Error,   "Event '{0}' arguments are not accessible here",                                                                                        DiagnosticCategory.Structure,
            FixHint: "Event arguments are only accessible in 'on EventName' clauses and the transition body"),
        DiagnosticCode.InvalidInterpolationCoercion   => new(nameof(DiagnosticCode.InvalidInterpolationCoercion),   DiagnosticStage.Type,  Severity.Error,   "A {0} value cannot appear inside a text interpolation",                                                                                DiagnosticCategory.TypeSystem,
            FixHint: "Convert this value to text before interpolating, or remove it from the text literal"),
        DiagnosticCode.UnresolvedTypedConstant        => new(nameof(DiagnosticCode.UnresolvedTypedConstant),        DiagnosticStage.Type,  Severity.Error,   "Cannot determine the type of '{0}' — no type context available",                                                                       DiagnosticCategory.TypeSystem,
            FixHint: "Place this constant where the type is unambiguous, such as in a typed field assignment"),
        DiagnosticCode.InvalidTypedConstantContent    => new(nameof(DiagnosticCode.InvalidTypedConstantContent),    DiagnosticStage.Type,  Severity.Error,   "'{0}' is not a valid {1} value",                                                                                                       DiagnosticCategory.TypeSystem),
        DiagnosticCode.DefaultForwardReference        => new(nameof(DiagnosticCode.DefaultForwardReference),        DiagnosticStage.Type,  Severity.Error,   "Default value for '{0}' cannot reference '{1}', which is declared later",                                                              DiagnosticCategory.Structure,
            FixHint: "Reorder field declarations so the referenced field appears before the one with the default"),

        // ── Type (temporal) ──────────────────────────────────────────────────────
        DiagnosticCode.InvalidDateValue               => new(nameof(DiagnosticCode.InvalidDateValue),               DiagnosticStage.Type,  Severity.Error,   "Invalid date: {0} does not exist",                                                                                                     DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.InvalidDateFormat],
            FixHint: "Check that the day, month, and year form a valid calendar date"),
        DiagnosticCode.InvalidDateFormat              => new(nameof(DiagnosticCode.InvalidDateFormat),              DiagnosticStage.Type,  Severity.Error,   "Dates must be written as YYYY-MM-DD. Use '{0}'",                                                                                       DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.InvalidDateValue, DiagnosticCode.InvalidTimeValue, DiagnosticCode.InvalidInstantFormat]),
        DiagnosticCode.InvalidTimeValue               => new(nameof(DiagnosticCode.InvalidTimeValue),               DiagnosticStage.Type,  Severity.Error,   "Invalid time: {0} must be 0\u201323 for hours, 0\u201359 for minutes and seconds",                                                     DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.InvalidDateFormat, DiagnosticCode.InvalidInstantFormat],
            FixHint: "Use hours 0–23 and minutes/seconds 0–59"),
        DiagnosticCode.InvalidInstantFormat           => new(nameof(DiagnosticCode.InvalidInstantFormat),           DiagnosticStage.Type,  Severity.Error,   "Instants must end with Z to indicate UTC. Use '{0}Z'",                                                                                  DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.InvalidDateFormat, DiagnosticCode.InvalidTimeValue]),
        DiagnosticCode.InvalidTimezoneId              => new(nameof(DiagnosticCode.InvalidTimezoneId),              DiagnosticStage.Type,  Severity.Error,   "'{0}' is not a recognized timezone — use canonical IANA form like 'America/New_York'",                                                  DiagnosticCategory.Temporal,
            FixHint: "Use a canonical IANA timezone ID such as 'America/New_York' or 'Europe/London'"),
        DiagnosticCode.UnqualifiedPeriodArithmetic    => new(nameof(DiagnosticCode.UnqualifiedPeriodArithmetic),    DiagnosticStage.Type,  Severity.Error,   "Period field '{0}' may contain {1} components — use period of '{2}' to constrain it",                                                  DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.MissingTemporalUnit],
            FixHint: "Add 'period of DimensionUnit' to constrain the period to a single unit"),
        DiagnosticCode.MissingTemporalUnit            => new(nameof(DiagnosticCode.MissingTemporalUnit),            DiagnosticStage.Type,  Severity.Error,   "A bare number doesn't specify a unit. Use '{0}' + '{1}' to add {1}",                                                                   DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.UnqualifiedPeriodArithmetic],
            FixHint: "Add a temporal unit keyword after the number, such as 'days' or 'hours'"),
        DiagnosticCode.FractionalUnitValue            => new(nameof(DiagnosticCode.FractionalUnitValue),            DiagnosticStage.Type,  Severity.Error,   "Unit values must be whole numbers. Use smaller units for fractions: '{0}'",                                                             DiagnosticCategory.Temporal,
            FixHint: "Use a smaller unit (e.g., 'minutes' instead of 'hours') to avoid fractional values"),

        // ── Type (collection safety) ─────────────────────────────────────────────
        DiagnosticCode.UnguardedCollectionAccess      => new(nameof(DiagnosticCode.UnguardedCollectionAccess),      DiagnosticStage.Type,  Severity.Error,   "'{0}' may be empty — guard with if {0}.count > 0 before accessing .{1}",                                                               DiagnosticCategory.Safety,
            RelatedCodes: [DiagnosticCode.UnguardedCollectionMutation],
            FixHint: "Add 'when CollectionField.count > 0' to the guard before accessing this member",
            PreventsFault: FaultCode.CollectionEmptyOnAccess),
        DiagnosticCode.UnguardedCollectionMutation    => new(nameof(DiagnosticCode.UnguardedCollectionMutation),    DiagnosticStage.Type,  Severity.Error,   "'{0}' may be empty — guard with if {0}.count > 0 before {1}",                                                                          DiagnosticCategory.Safety,
            RelatedCodes: [DiagnosticCode.UnguardedCollectionAccess],
            FixHint: "Add 'when CollectionField.count > 0' to the guard before this action",
            PreventsFault: FaultCode.CollectionEmptyOnMutation),
        DiagnosticCode.NonOrderableCollectionExtreme  => new(nameof(DiagnosticCode.NonOrderableCollectionExtreme),  DiagnosticStage.Type,  Severity.Error,   "'.{1}' requires an orderable element type — '{0}' elements have no natural ordering",                                                  DiagnosticCategory.TypeSystem,
            FixHint: "Change the collection element type to an orderable type, or use .count instead"),
        DiagnosticCode.CaseInsensitiveStringOnNonCollection => new(nameof(DiagnosticCode.CaseInsensitiveStringOnNonCollection), DiagnosticStage.Type, Severity.Error, "~string is only valid as a collection inner type — use string for field declarations",                                               DiagnosticCategory.TypeSystem,
            FixHint: "Use '~string' only as a collection element type, e.g., 'set of ~string'"),

        // ── Type (business-domain) ───────────────────────────────────────────────
        DiagnosticCode.MaxPlacesExceeded              => new(nameof(DiagnosticCode.MaxPlacesExceeded),              DiagnosticStage.Type,  Severity.Error,   "Value has {0} decimal places, but field '{1}' allows at most {2}",                                                                     DiagnosticCategory.BusinessDomain,
            FixHint: "Increase the 'maxplaces' constraint, or use a value with fewer decimal places"),
        DiagnosticCode.QualifierMismatch              => new(nameof(DiagnosticCode.QualifierMismatch),              DiagnosticStage.Type,  Severity.Error,   "Value does not match the '{0}' qualifier on field '{1}'",                                                                              DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.MutuallyExclusiveQualifiers],
            FixHint: "Match the qualifier value in the expression to the qualifier declared on the field",
            PreventsFault: FaultCode.QualifierMismatch),
        DiagnosticCode.DimensionCategoryMismatch      => new(nameof(DiagnosticCode.DimensionCategoryMismatch),      DiagnosticStage.Type,  Severity.Error,   "Dimension '{0}' does not match the declared category '{1}' on field '{2}'",                                                            DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.CrossDimensionArithmetic],
            FixHint: "Use a unit whose dimension matches the declared dimension category on the field"),
        DiagnosticCode.CrossCurrencyArithmetic        => new(nameof(DiagnosticCode.CrossCurrencyArithmetic),        DiagnosticStage.Type,  Severity.Error,   "Cannot combine '{0}' ({1}) with '{2}' ({3}) — different currencies",                                                                   DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.CrossDimensionArithmetic],
            FixHint: "Convert amounts to the same currency before combining them"),
        DiagnosticCode.CrossDimensionArithmetic       => new(nameof(DiagnosticCode.CrossDimensionArithmetic),       DiagnosticStage.Type,  Severity.Error,   "Cannot combine '{0}' ({1}) with '{2}' ({3}) — incompatible dimensions",                                                               DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.CrossCurrencyArithmetic, DiagnosticCode.DimensionCategoryMismatch],
            FixHint: "Convert quantities to the same unit before combining them"),
        DiagnosticCode.DenominatorUnitMismatch        => new(nameof(DiagnosticCode.DenominatorUnitMismatch),        DiagnosticStage.Type,  Severity.Error,   "Denominator unit '{0}' does not match operand unit '{1}'",                                                                             DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.DurationDenominatorMismatch, DiagnosticCode.CompoundPeriodDenominator],
            FixHint: "Use the same unit for the denominator as the operand"),
        DiagnosticCode.DurationDenominatorMismatch    => new(nameof(DiagnosticCode.DurationDenominatorMismatch),    DiagnosticStage.Type,  Severity.Error,   "Duration cannot cancel '{0}' denominator — days, weeks, months, and years have variable length",                                       DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.DenominatorUnitMismatch, DiagnosticCode.CompoundPeriodDenominator],
            FixHint: "Use only fixed-length units (hours, minutes, seconds) as duration denominators"),
        DiagnosticCode.CompoundPeriodDenominator      => new(nameof(DiagnosticCode.CompoundPeriodDenominator),      DiagnosticStage.Type,  Severity.Error,   "Compound period '{0}' cannot cancel single-unit denominator '{1}'",                                                                    DiagnosticCategory.Temporal,
            RelatedCodes: [DiagnosticCode.DenominatorUnitMismatch, DiagnosticCode.DurationDenominatorMismatch],
            FixHint: "Use a single-unit period instead of a compound period as the denominator"),
        DiagnosticCode.InvalidUnitString              => new(nameof(DiagnosticCode.InvalidUnitString),              DiagnosticStage.Type,  Severity.Error,   "'{0}' is not a valid unit",                                                                                                            DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.InvalidCurrencyCode, DiagnosticCode.InvalidDimensionString],
            FixHint: "Use a recognized unit identifier, such as 'kg', 'miles', or 'liters'"),
        DiagnosticCode.InvalidCurrencyCode            => new(nameof(DiagnosticCode.InvalidCurrencyCode),            DiagnosticStage.Type,  Severity.Error,   "'{0}' is not a recognized ISO 4217 currency code",                                                                                     DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.InvalidUnitString, DiagnosticCode.InvalidDimensionString],
            FixHint: "Use a valid ISO 4217 currency code, such as 'USD', 'EUR', or 'GBP'"),
        DiagnosticCode.InvalidDimensionString         => new(nameof(DiagnosticCode.InvalidDimensionString),         DiagnosticStage.Type,  Severity.Error,   "'{0}' is not a recognized dimension",                                                                                                  DiagnosticCategory.BusinessDomain,
            RelatedCodes: [DiagnosticCode.InvalidUnitString, DiagnosticCode.InvalidCurrencyCode],
            FixHint: "Use a recognized dimension identifier, such as 'length', 'mass', or 'time'"),

        // ── Runtime / value safety ────────────────────────────────────────────────
        DiagnosticCode.NumericOverflow                => new(nameof(DiagnosticCode.NumericOverflow),                DiagnosticStage.Type,  Severity.Error,   "Numeric computation exceeded the representable range on field '{0}'",                                                                  DiagnosticCategory.Safety,
            FixHint: "Reduce the magnitude of operands, or widen the field type to number",
            PreventsFault: FaultCode.NumericOverflow),
        DiagnosticCode.OutOfRange                     => new(nameof(DiagnosticCode.OutOfRange),                     DiagnosticStage.Type,  Severity.Error,   "Value is outside the declared bounds for field '{0}'",                                                                                 DiagnosticCategory.Safety,
            RelatedCodes: [DiagnosticCode.InvalidModifierBounds],
            FixHint: "Ensure assigned values satisfy the field's min/max constraints, or widen the bounds",
            PreventsFault: FaultCode.OutOfRange),

        // ── Graph ─────────────────────────────────────────────────────────────────
        DiagnosticCode.UnreachableState               => new(nameof(DiagnosticCode.UnreachableState),               DiagnosticStage.Graph, Severity.Warning, "State '{0}' is unreachable from initial state '{1}'",                                                                                  DiagnosticCategory.Structure,
            RelatedCodes: [DiagnosticCode.UnhandledEvent],
            FixHint: "Add a transition to this state, or remove it if it is no longer needed"),
        DiagnosticCode.UnhandledEvent                 => new(nameof(DiagnosticCode.UnhandledEvent),                 DiagnosticStage.Graph, Severity.Warning, "No transition handles event '{0}' in state '{1}' — firing it will always be rejected",                                                 DiagnosticCategory.Structure,
            RelatedCodes: [DiagnosticCode.UnreachableState],
            FixHint: "Add a transition that handles this event in this state, or remove the event"),

        // ── Proof ─────────────────────────────────────────────────────────────────
        DiagnosticCode.UnsatisfiableGuard             => new(nameof(DiagnosticCode.UnsatisfiableGuard),             DiagnosticStage.Proof, Severity.Warning, "The condition '{0}' on event '{1}' can never be true when {2} — this transition will never fire",                                      DiagnosticCategory.Proof,
            RelatedCodes: [DiagnosticCode.DivisionByZero, DiagnosticCode.SqrtOfNegative],
            FixHint: "Revise the guard condition so it can be satisfied, or remove the transition"),
        DiagnosticCode.DivisionByZero                 => new(nameof(DiagnosticCode.DivisionByZero),                 DiagnosticStage.Proof, Severity.Error,   "Division by zero: '{0}' can be zero when {1}",                                                                                         DiagnosticCategory.Proof,
            RelatedCodes: [DiagnosticCode.SqrtOfNegative, DiagnosticCode.UnsatisfiableGuard],
            FixHint: "Add a guard that ensures the divisor is nonzero, e.g., 'when Divisor != 0'",
            PreventsFault: FaultCode.DivisionByZero),
        DiagnosticCode.SqrtOfNegative                 => new(nameof(DiagnosticCode.SqrtOfNegative),                 DiagnosticStage.Proof, Severity.Error,   "sqrt() requires a non-negative value, but '{0}' can be negative when {1}",                                                             DiagnosticCategory.Proof,
            RelatedCodes: [DiagnosticCode.DivisionByZero, DiagnosticCode.UnsatisfiableGuard],
            FixHint: "Add a guard that ensures the value is nonnegative, e.g., 'when Value >= 0'",
            PreventsFault: FaultCode.SqrtOfNegative),

        _ => throw new ArgumentOutOfRangeException(nameof(code), code, null),
    };

    public static Diagnostic Create(DiagnosticCode code, SourceSpan span, params object?[] args)
    {
        var meta = GetMeta(code);
        return new(meta.Severity, meta.Stage, meta.Code, string.Format(meta.MessageTemplate, args), span);
    }

    public static IReadOnlyList<DiagnosticMeta> All { get; } =
        Enum.GetValues<DiagnosticCode>().Select(GetMeta).ToList();
}
